LibCodex:_FeedBundledRows("Holidays", "id,label,region,description,flags,sources,descriptionID,filterType,looping,nameID,priority", {
    {62,"Fireworks Spectacular",0,"After the sun sets, the end of Midsummer is celebrated, with an hourly firework extravaganza.\n\n\n\nTo watch the show, visit any capital city or Booty Bay.",1,{"wago"},11,255,0,12,4},
    {141,"Feast of Winter Veil",0,"Greatfather Winter is visiting the cities of Ironforge and Orgrimmar, courtesy of Smokywood Pastures.  And throughout Azeroth, it is the season to be jolly!",1,{"wago"},13,255,0,14,5},
    {181,"Noblegarden",0,"The feast of Noblegarden has arrived.  The proving grounds of each race, the place where young heroes first test their strength, each holds cleverly hidden treasure eggs.  How many can you find?",1,{"wago"},14,255,0,15,5},
    {201,"Children's Week",0,"Show an orphan what the hero's life is like!  Visit Orphan Matron Nightingale in Stormwind, Orphan Matron Battlewail in Orgrimmar, Orphan Matron Mercy in Shattrath, Orphan Matron Aria in Dalaran, Caretaker Padae in Dazar'alor, Orphan Matron Westerson in Boralus, or Ullna in Dornogal and make a child's dream come true.",1,{"wago"},12,255,0,13,5},
    {283,"Call to Arms: Alterac Valley",0,"The battle for Alterac Valley grows intense.  Greater honor is given to those who pledge sword to their liege and battle in Alterac.",1,{"wago"},22,2,0,22,0},
    {284,"Call to Arms: Warsong Gulch",0,"The battle for Warsong Gulch grows intense.  Greater honor is given to those who pledge sword to their liege and battle in the Gulch.",1,{"wago"},25,2,0,25,0},
    {285,"Call to Arms: Arathi Basin",0,"The battle for Arathi Basin grows intense.  Greater honor is given to those who pledge sword to their liege and battle in Arathi.",1,{"wago"},23,2,0,23,0},
    {321,"Harvest Festival",0,"The Harvest Festival is a time to commemorate those  who have sacrificed their lives to help friends and allies.  Feasts are held outside Orgrimmar and Ironforge in honor of these fallen heroes.",1,{"wago"},16,255,0,17,5},
    {324,"Hallow's End",0,"Hallow's End celebrates the break of the Forsaken from the Scourge.\n\n\n\nFun and mischief reign as the Innkeepers of Azeroth give treats, and tricks, to whomever asks.",1,{"wago"},15,255,0,16,5},
    {327,"Lunar Festival",0,"Every year the druids of Moonglade hold a celebration of their city's great triumph over an ancient evil. During the Lunar Festival, citizens of Azeroth have the opportunity to honor their elders by celebrating their sage wisdom, sharing in magnificent feasts, and of course... shooting lots of fireworks!",1,{"wago"},17,255,0,18,5},
    {335,"Love is in the Air",0,"Something is in the air in the major cities of Azeroth. Artisans have come together to put on the Gala of Gifts, where townsfolk can get tokens of kindness and affection for their loved ones.",1,{"wago"},9,255,0,9,5},
    {341,"Midsummer Fire Festival",0,"A time of merriment and celebration, dedicated to the hottest season of the year.",1,{"wago"},10,255,0,11,5},
    {353,"Call to Arms: Eye of the Storm",0,"The battle for the Eye of the Storm grows intense.  Greater honor is given to those who pledge sword to their liege and battle in the Eye.",1,{"wago"},24,2,0,24,0},
    {372,"Brewfest",0,"First celebrated by the dwarves, Brewfest now holds appeal among all the races of Azeroth!\n\n\n\nVisit the Alliance camp outside Ironforge, or the Horde camp outside Orgrimmar, and join the party!",1,{"wago"},8,255,0,7,6},
    {398,"Pirates' Day",0,"Captain DeMeza sails to the goblin town of Booty Bay and recruits land-lovers into her buccaneer ranks.\n\n\n\nVisit her or her henchmen in the capital cities if the pirate's life is for you!",1,{"wago"},21,255,0,21,5},
    {400,"Call to Arms: Strand of the Ancients",0,"The battle for the Strand of the Ancients grows intense.  Greater honor is given to those who pledge sword to their liege and battle upon the Strand.",1,{"wago"},41,2,0,41,0},
    {404,"Pilgrim's Bounty",0,"Pilgrim's Bounty is a time to reflect upon one's good fortune and share with all around you.",1,{"wago"},101,255,0,101,5},
    {406,"Wrath of the Lich King Launch",0,"The Wrath of the Lich King launches on November 13th.\n\n\n\nAlliance ships depart from Stormwind and Menethil Harbor.\n\n\n\nHorde Zeppelins leave from outside Orgrimmar and Undercity.\n\n\n\nSee you in Northrend...",0,{"wago"},61,255,0,61,0},
    {409,"Day of the Dead",1999,"During the Day of the Dead, people gather in graveyards to celebrate with and cherish the spirits of those they have lost.\n\n\n\nOne can find the festivities in the cemeteries of many major cities, where celebrants cook, dance, don costumes, and more.",1,{"wago"},81,255,0,81,10},
    {420,"Call to Arms: Isle of Conquest",0,"The battle for the Isle of Conquest grows intense.  Greater honor is given to those who pledge sword to their liege and battle upon the Isle.",1,{"wago"},121,2,0,121,0},
    {423,"Love is in the Air",0,"Something is in the air in the major cities of Azeroth. Artisans have come together to put on the Gala of Gifts, where townsfolk can get tokens of kindness and affection for their loved ones.",1,{"wago"},9,255,0,9,5},
    {424,"Kalu'ak Fishing Derby",0,"The Kalu'ak hold a fishing derby every few days in Northrend.  Be the first to catch a Blacktip Shark and win respect with the Kalu'ak, and an amazing prize!",1,{"wago"},161,0,0,161,0},
    {435,"Call to Arms: The Battle for Gilneas",0,"The battle for Gilneas continues in the once-proud city, where invading Forsaken attempt to wrest control from its cursed defenders street by bloody street.",1,{"wago"},162,2,0,162,0},
    {436,"Call to Arms: Twin Peaks",0,"For more than twenty years the Wildhammer dwarves and Dragonmaw orcs have clashed over the fertile valleys of Azeroth's eastern highlands.",1,{"wago"},163,2,0,163,0},
    {442,"Rated BG: 15v15",0,"15v15 rated battlegrounds are available.  Join a group with 14 other players and queue for a rated battleground from the PvP menu to earn Conquest Points.",1,{"wago"},165,2,1,165,0},
    {443,"Rated BG: 25v25",0,"25v25 rated battlegrounds are available.  Join a group with 24 other players and queue for a rated battleground from the PvP menu to earn Conquest Points.",1,{"wago"},166,2,0,166,0},
    {467,"WoW's 7th Anniversary",0,"It's World of Warcraft's anniversary!\n\n\n\nMany thanks from the WoW Dev Team for enjoying the world of Azeroth and beyond with us.",1,{"wago"},188,255,0,203,0},
    {479,"Darkmoon Faire",0,"The Darkmoon Faire is open for business! \n\n\n\nMeet Silas Darkmoon and his troupe, play games that test mind and nerve, and behold exotic sights from the four corners of Azeroth... and beyond!",1,{"wago"},201,1,0,1,1},
    {484,"WoW's 8th Anniversary",0,"It's World of Warcraft's anniversary!\n\n\n\nMany thanks from the WoW Dev Team for enjoying the world of Azeroth and beyond with us.",1,{"wago"},188,255,0,220,0},
    {488,"Call to Arms: Silvershard Mines",0,"The profiteering Venture Co. has managed to sell the Silvershard Mines rights to both the Alliance and Horde! Even now, mercenaries hired by rival mining operations from Ironforge and Bilgewater Bay clash over the precious resources...",1,{"wago"},204,2,0,222,0},
